"""Sample Python module for testing."""


def add(x: int, y: int) -> int:
    """Add two numbers."""
    return x + y


class Calculator:
    """A simple calculator."""

    def multiply(self, x: int, y: int) -> int:
        """Multiply two numbers."""
        return x * y

    def divide(self, x: float, y: float) -> float:
        return x / y
